
from scipy._lib.deprecation import _sub_module_deprecation


__all__ = [  # noqa: F822
    'spalde',
    'splder',
    'splev',
    'splint',
    'sproot',
]


def __dir__():
    return __all__


def __getattr__(name):
    return _sub_module_deprecation(sub_package="interpolate", module="dfitpack",
                                   private_modules=["_dfitpack"], all=__all__,
                                   attribute=name)
